// 1. CONFIGURE YOUR PHYSICAL COORDINATES HERE
const OBSERVER_LAT = 51.0447;   // Your Latitude
const OBSERVER_LON = -114.0719; // Your Longitude

// Safe Global Retrieval
let rawData = global.get("rawStarlinkData");
if (!rawData || typeof rawData !== 'string' || rawData.trim() === "") {
    return null;
}

const deg2rad = Math.PI / 180;
const lines = rawData.split('\n');
const visibleSatellites = [];

// Greenwich Apparent Sidereal Time — converts ECI longitude to Earth-fixed longitude
const J2000_ms = 946728000000;
const t_J2000 = (Date.now() - J2000_ms) / 86400000;
const GAST = (280.46061837 + 360.98564736629 * t_J2000) % 360;

const Re = 6371; // Earth radius (km)
const h  = 550;  // Starlink orbital altitude (km)
const obs_lat = OBSERVER_LAT * deg2rad;
const obs_lon = OBSERVER_LON * deg2rad;

for (let i = 0; i < lines.length; i++) {
    const row = lines[i].split(',');
    if (row.length < 9 || !row[0] || !row[0].startsWith("STARLINK")) continue;

    const name = row[0].trim();
    const n    = parseFloat(row[3]); // mean motion (rev/day)
    const inc  = parseFloat(row[5]) * deg2rad;
    const raan = parseFloat(row[6]); // RAAN at epoch (degrees, ECI)
    const argp = parseFloat(row[7]); // arg of pericenter (degrees)
    const M0   = parseFloat(row[8]); // mean anomaly at epoch (degrees)

    if (isNaN(n) || isNaN(inc) || isNaN(raan) || isNaN(argp) || isNaN(M0)) continue;

    try {
        // Propagate mean anomaly from epoch to now
        const epoch_ms = new Date(row[2].trim()).getTime();
        const dt_days = (Date.now() - epoch_ms) / 86400000;
        const M = (M0 + n * dt_days * 360) % 360;

        // Argument of latitude (ω + M; low-eccentricity orbits: M ≈ true anomaly)
        const u = (argp + M) * deg2rad;

        // Sub-satellite point in geocentric coordinates
        const sat_lat = Math.asin(Math.max(-1, Math.min(1, Math.sin(inc) * Math.sin(u))));
        const lon_offset = Math.atan2(Math.cos(inc) * Math.sin(u), Math.cos(u)) / deg2rad;

        // Convert ECI longitude to Earth-fixed (ECEF) using GAST
        let sat_lon = ((raan + lon_offset) - GAST) % 360;
        if (sat_lon > 180) sat_lon -= 360;

        // Central angle between observer and sub-satellite point
        const dlon = sat_lon * deg2rad - obs_lon;
        const cos_c = Math.sin(obs_lat) * Math.sin(sat_lat) +
                      Math.cos(obs_lat) * Math.cos(sat_lat) * Math.cos(dlon);

        // Quick below-horizon reject
        if (cos_c < Re / (Re + h)) continue;

        const c = Math.acos(Math.max(-1, Math.min(1, cos_c)));
        const elevation = Math.atan((cos_c - Re / (Re + h)) / Math.sin(c)) / deg2rad;
        if (elevation <= 0) continue;

        // Azimuth (bearing from observer to sub-satellite point)
        const az = (Math.atan2(
            Math.sin(dlon) * Math.cos(sat_lat),
            Math.cos(obs_lat) * Math.sin(sat_lat) - Math.sin(obs_lat) * Math.cos(sat_lat) * Math.cos(dlon)
        ) / deg2rad + 360) % 360;

        // Polar radar mapping: zenith = center (radius 0), horizon = edge (radius 90)
        const radius = 90 - elevation;
        const angleRad = (az - 90) * deg2rad;
        visibleSatellites.push({
            x: parseFloat((radius * Math.cos(angleRad)).toFixed(2)),
            y: parseFloat((radius * Math.sin(angleRad)).toFixed(2)),
            label: name
        });
    } catch(e) {}
}

msg.topic = "Starlink";
msg.payload = visibleSatellites.slice(0, 500);
return msg;

// Save the raw text into global memory so other nodes can access it
global.set("rawStarlinkData", msg.payload.toString());
return null; // Stop the message here so it doesn't trigger the map graph yet

// Check if local cache is fresh enough (< 2 hours)
const CACHE = '/data/starlink_tle_cache.csv';
const TWO_HOURS = 2 * 60 * 60 * 1000;
try {
    const stat = fs.statSync(CACHE);
    const age  = Date.now() - stat.mtimeMs;
    if (age < TWO_HOURS) {
        const data = fs.readFileSync(CACHE, 'utf8');
        global.set('rawStarlinkData', data);
        global.set('satHistory', {});
        node.status({fill:'green', shape:'dot', text:`cache ${Math.round(age/60000)}m old`});
        return null; // skip HTTP fetch
    }
} catch(e) { /* no cache yet */ }
return msg; // cache stale or missing — fetch

// Route: success → port 1, HTTP error → port 2 (cache fallback)
if (msg.error || (msg.statusCode && msg.statusCode !== 200)) {
    node.warn('HTTP fetch failed (' + (msg.error || msg.statusCode) + ') — trying cache');
    return [null, msg];
}
return [msg, null];

// Save fresh TLE data to cache file and load into global
const CACHE = '/data/starlink_tle_cache.csv';
try {
    fs.writeFileSync(CACHE, msg.payload);
} catch(e) {
    node.warn('Could not write cache: ' + e.message);
}
global.set('rawStarlinkData', msg.payload);
global.set('satHistory', {});
node.status({fill:'blue', shape:'dot', text:`fetched ${new Date().toLocaleTimeString()}`});
return null;

// HTTP failed — load from cache file if available
const CACHE = '/data/starlink_tle_cache.csv';
try {
    const data = fs.readFileSync(CACHE, 'utf8');
    global.set('rawStarlinkData', data);
    global.set('satHistory', {});
    node.status({fill:'yellow', shape:'ring', text:`HTTP error, using cache ${new Date().toLocaleTimeString()}`});
} catch(e) {
    node.error('HTTP fetch failed and no cache available: ' + e.message);
}
return null;
